import React, { useState } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

const LINKS = [
  { path:"/dashboard",    icon:"⬡",  label:"Home" },
  { path:"/analysis",     icon:"🔍", label:"Analyze" },
  { path:"/roadmap",      icon:"🗺️", label:"Roadmap" },
  { path:"/study-plan",   icon:"📅", label:"Study" },
  { path:"/interview",    icon:"💼", label:"Interview" },
  { path:"/assistant",    icon:"🤖", label:"AI Chat" },
];

const SOCIAL = [
  { path:"/community",    icon:"👥", label:"Community" },
  { path:"/chat",         icon:"💬", label:"Chat" },
  { path:"/jobs",         icon:"🏢", label:"Jobs" },
  { path:"/challenges",   icon:"🏆", label:"Challenges" },
  { path:"/certificates", icon:"📜", label:"Certs" },
  { path:"/leaderboard",  icon:"📊", label:"Leaderboard" },
  { path:"/events",       icon:"🎯", label:"Events" },
  { path:"/mentors",      icon:"🎓", label:"Mentors" },
];

export default function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [expanded, setExpanded] = useState(false);
  const isActive = (p) => location.pathname === p;

  const navLink = (link) => (
    <Link key={link.path} to={link.path} style={{
      display:"flex", alignItems:"center", gap:".4rem",
      padding:".4rem .8rem", borderRadius:"8px", textDecoration:"none",
      fontSize:".82rem", fontWeight: isActive(link.path) ? 600 : 400,
      color: isActive(link.path) ? "var(--blue)" : "var(--muted)",
      background: isActive(link.path) ? "rgba(61,142,240,.1)" : "transparent",
      border: isActive(link.path) ? "1px solid rgba(61,142,240,.2)" : "1px solid transparent",
      transition:"all .2s",
    }}>
      {link.icon} {link.label}
    </Link>
  );

  return (
    <nav style={{ background:"rgba(6,13,26,.95)", borderBottom:"1px solid var(--border)", padding:".7rem 1.25rem", display:"flex", alignItems:"center", justifyContent:"space-between", position:"sticky", top:0, zIndex:200, backdropFilter:"blur(12px)" }}>
      {/* Logo */}
      <Link to="/dashboard" style={{ textDecoration:"none", display:"flex", alignItems:"center", gap:".5rem", flexShrink:0 }}>
        <div style={{ width:30, height:30, background:"linear-gradient(135deg,var(--blue),var(--purple))", borderRadius:8, display:"flex", alignItems:"center", justifyContent:"center", fontSize:".9rem" }}>⬡</div>
        <span style={{ fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:"1.1rem", color:"#fff" }}>
          SkillGraph<span style={{ color:"var(--purple)" }}>AI</span>
        </span>
      </Link>

      {/* Main links */}
      <div style={{ display:"flex", gap:".2rem", alignItems:"center", flexWrap:"wrap" }}>
        {LINKS.map(navLink)}
        {/* More dropdown */}
        <div style={{ position:"relative" }}>
          <button onClick={() => setExpanded(!expanded)} className="sg-btn sg-btn-outline sg-btn-sm" style={{ gap:".3rem" }}>
            More {expanded ? "▲" : "▼"}
          </button>
          {expanded && (
            <div style={{ position:"absolute", top:"calc(100% + .5rem)", left:0, background:"var(--bg2)", border:"1px solid var(--border)", borderRadius:12, padding:".5rem", minWidth:160, zIndex:300, display:"grid", gridTemplateColumns:"1fr 1fr", gap:".25rem", boxShadow:"0 8px 30px rgba(0,0,0,.4)" }}>
              {SOCIAL.map(l => (
                <Link key={l.path} to={l.path} onClick={() => setExpanded(false)} style={{ display:"flex", alignItems:"center", gap:".4rem", padding:".45rem .7rem", borderRadius:8, textDecoration:"none", fontSize:".8rem", color: isActive(l.path) ? "var(--blue)" : "var(--muted)", background: isActive(l.path) ? "rgba(61,142,240,.1)" : "transparent", transition:"all .15s" }}
                  onMouseEnter={e => e.currentTarget.style.background = "var(--bg3)"}
                  onMouseLeave={e => e.currentTarget.style.background = isActive(l.path) ? "rgba(61,142,240,.1)" : "transparent"}>
                  {l.icon} {l.label}
                </Link>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* User */}
      <div style={{ display:"flex", alignItems:"center", gap:".6rem", flexShrink:0 }}>
        {/* Streak */}
        {user?.streak > 0 && (
          <div style={{ background:"rgba(246,173,85,.1)", border:"1px solid rgba(246,173,85,.3)", borderRadius:8, padding:".3rem .7rem", fontSize:".75rem", color:"var(--amber)" }}>
            🔥 {user.streak}d
          </div>
        )}
        {/* Points */}
        <div style={{ background:"rgba(56,226,154,.08)", border:"1px solid rgba(56,226,154,.2)", borderRadius:8, padding:".3rem .7rem", fontSize:".75rem", color:"var(--green)" }}>
          ⭐ {user?.points || 0}
        </div>
        <Link to="/profile" style={{ textDecoration:"none", display:"flex", alignItems:"center", gap:".4rem", background:"var(--bg3)", border:"1px solid var(--border)", borderRadius:8, padding:".3rem .8rem" }}>
          <div className="sg-avatar" style={{ width:24, height:24, fontSize:".7rem" }}>
            {user?.avatar ? <img src={user.avatar} alt="" style={{ width:24, height:24, borderRadius:"50%" }}/> : user?.name?.[0]?.toUpperCase()}
          </div>
          <span style={{ color:"var(--muted)", fontSize:".8rem" }}>{user?.name?.split(" ")[0]}</span>
        </Link>
        <button onClick={() => { logout(); navigate("/"); }} className="sg-btn sg-btn-outline sg-btn-sm">
          Out
        </button>
      </div>
    </nav>
  );
}
